import { Link } from "react-router-dom";

function Navbar() {
  return (
    <nav style={{ padding: 10, background: "#222" }}>
      <Link to="/" style={{ color: "white", marginRight: 15 }}>Home</Link>
      <Link to="/matches" style={{ color: "white", marginRight: 15 }}>Matches</Link>
      <Link to="/players" style={{ color: "white" }}>Players</Link>
    </nav>
  );
}

export default Navbar;
